// The function's ensures (re-applied to both runs) is `HashMap::swap_spec`.
// Inside this synthetic det check the two `swap_spec` calls appear only in
// the antecedent of the conditional postcondition, so we re-assert every
// useful consequence as a *tautological* implication `H ==> P`. Each
// implication is unconditionally true because `swap_spec` is `pub open spec`
// and unfolds to `put_spec` (the insert equality) together with the
// `get_spec` match (the ack-state equality).
//
// Step 1 — `put_spec` pins both `post*_self_.epmap@` to the *same* term
// `pre_self_.epmap@.insert(src@, pre_ack_state)`, so the two views coincide.
// We lift each side individually, then chain them, and also re-state the
// equality with `=~=` (Map extensionality) so z3 has both flavors available
// across the two runs without re-instantiating `Map::insert` axioms.
assert((HashMap::swap_spec(pre_self_.epmap@, post1_self_.epmap@, src@, pre_ack_state, post1_ack_state, default)
        && HashMap::swap_spec(pre_self_.epmap@, post2_self_.epmap@, src@, pre_ack_state, post2_ack_state, default))
       ==> post1_self_.epmap@ == pre_self_.epmap@.insert(src@, pre_ack_state));

assert((HashMap::swap_spec(pre_self_.epmap@, post1_self_.epmap@, src@, pre_ack_state, post1_ack_state, default)
        && HashMap::swap_spec(pre_self_.epmap@, post2_self_.epmap@, src@, pre_ack_state, post2_ack_state, default))
       ==> post2_self_.epmap@ == pre_self_.epmap@.insert(src@, pre_ack_state));

assert((HashMap::swap_spec(pre_self_.epmap@, post1_self_.epmap@, src@, pre_ack_state, post1_ack_state, default)
        && HashMap::swap_spec(pre_self_.epmap@, post2_self_.epmap@, src@, pre_ack_state, post2_ack_state, default))
       ==> post1_self_.epmap@ == post2_self_.epmap@);

assert((HashMap::swap_spec(pre_self_.epmap@, post1_self_.epmap@, src@, pre_ack_state, post1_ack_state, default)
        && HashMap::swap_spec(pre_self_.epmap@, post2_self_.epmap@, src@, pre_ack_state, post2_ack_state, default))
       ==> post1_self_.epmap@ =~= post2_self_.epmap@);

// Step 2 — the `get_spec` match inside `swap_spec` binds both
// `post*_ack_state` to the same witness (`Some(v) -> v`, `None -> default`),
// so they are equal as full `CAckState` structs. From this, the per-field
// equalities on `num_packets_acked` and `un_acked` that
// `det_cack_state_swap_equal` checks follow by congruence.
assert((HashMap::swap_spec(pre_self_.epmap@, post1_self_.epmap@, src@, pre_ack_state, post1_ack_state, default)
        && HashMap::swap_spec(pre_self_.epmap@, post2_self_.epmap@, src@, pre_ack_state, post2_ack_state, default))
       ==> post1_ack_state == post2_ack_state);

assert((HashMap::swap_spec(pre_self_.epmap@, post1_self_.epmap@, src@, pre_ack_state, post1_ack_state, default)
        && HashMap::swap_spec(pre_self_.epmap@, post2_self_.epmap@, src@, pre_ack_state, post2_ack_state, default))
       ==> post1_ack_state.num_packets_acked == post2_ack_state.num_packets_acked);

assert((HashMap::swap_spec(pre_self_.epmap@, post1_self_.epmap@, src@, pre_ack_state, post1_ack_state, default)
        && HashMap::swap_spec(pre_self_.epmap@, post2_self_.epmap@, src@, pre_ack_state, post2_ack_state, default))
       ==> post1_ack_state.un_acked == post2_ack_state.un_acked);
